  function restoreSessionState() {
    if (!canUseSessionStorage) return;
    let payload;
    try {
      const raw = window.localStorage.getItem(getScopedStorageKey(SESSION_STORAGE_KEY));
      if (!raw) return;
      payload = JSON.parse(raw);
    } catch (error) {
      return;
    }
    if (!payload || typeof payload !== 'object') {
      return;
    }

    if (typeof payload.tool === 'string') {
      state.tool = normalizeToolId(payload.tool, state.tool);
    }
    if (Number.isFinite(payload.brushSize)) {
      state.brushSize = clamp(Math.round(payload.brushSize), 1, 32);
    }
    if (Number.isFinite(payload.outlineSize)) {
      state.outlineSize = clamp(Math.round(payload.outlineSize), 1, 8);
    }
	    if (typeof payload.selectSameMode === 'string') {
	      state.selectSameMode = normalizeSelectSameMode(payload.selectSameMode, state.selectSameMode);
	    }
    if (typeof payload.fillStyle === 'string') {
      state.fillStyle = normalizeFillStyle(payload.fillStyle, state.fillStyle);
    }
	    if (typeof payload.selectionShapeMode === 'string') {
	      state.selectionShapeMode = normalizeSelectionShapeMode(payload.selectionShapeMode, state.selectionShapeMode);
	    }
    if (Object.prototype.hasOwnProperty.call(payload, 'customBrush')) {
      state.customBrush = deserializeCustomBrushPayload(payload.customBrush);
    }
    if (typeof payload.brushShape === 'string') {
      state.brushShape = normalizeBrushShape(payload.brushShape, state.brushShape);
      if (state.brushShape === BRUSH_SHAPE_CUSTOM && !hasCustomBrushData()) {
        state.brushShape = BRUSH_SHAPE_SQUARE;
      }
    }
    if (typeof payload.showGrid === 'boolean') {
      state.showGrid = payload.showGrid;
    }
    if (Number.isFinite(payload.gridScreenStep)) {
      state.gridScreenStep = clamp(Math.round(payload.gridScreenStep), 1, 256);
    }
    if (typeof payload.showMajorGrid === 'boolean') {
      state.showMajorGrid = payload.showMajorGrid;
    }
    if (Number.isFinite(payload.majorGridSpacing)) {
      state.majorGridSpacing = clamp(Math.round(payload.majorGridSpacing), 2, 512);
    }
    if (payload.backgroundMode === 'light' || payload.backgroundMode === 'dark' || payload.backgroundMode === 'pink') {
      state.backgroundMode = payload.backgroundMode;
    }
    if (typeof payload.uiTheme === 'string') {
      state.uiTheme = normalizeUiTheme(payload.uiTheme, state.uiTheme);
    }
    if (payload.toolGroup && TOOL_GROUPS[payload.toolGroup]) {
      state.activeToolGroup = payload.toolGroup;
    }
    if (payload.lastGroupTool && typeof payload.lastGroupTool === 'object') {
      state.lastGroupTool = { ...DEFAULT_GROUP_TOOL, ...payload.lastGroupTool };
    }
    railSizing.left = RAIL_INITIAL_WIDTH.left;
    railSizing.right = RAIL_INITIAL_WIDTH.right;
    bottomTimelineSizing.height = BOTTOM_TIMELINE_INITIAL_HEIGHT;
    mobileDrawerState.mode = MOBILE_DRAWER_DEFAULT_MODE;
    if (payload.leftTab && LEFT_TAB_KEYS.includes(payload.leftTab)) {
      state.activeLeftTab = payload.leftTab;
    }
    if (payload.rightTab && RIGHT_TAB_KEYS.includes(payload.rightTab)) {
      state.activeRightTab = payload.rightTab;
    }
    if (typeof payload.showPixelGuides === 'boolean') {
      state.showPixelGuides = payload.showPixelGuides;
    }
    state.mirror = normalizeMirrorAxisState(payload.mirror, state.width, state.height);
    if (typeof payload.showVirtualCursor === 'boolean') {
      state.showVirtualCursor = payload.showVirtualCursor;
    }
    if (typeof payload.showCanvasResizeHandles === 'boolean') {
      state.showCanvasResizeHandles = payload.showCanvasResizeHandles;
    }
    if (Number.isFinite(payload.virtualCursorButtonScale)) {
      state.virtualCursorButtonScale = normalizeFloatingDrawButtonScale(payload.virtualCursorButtonScale);
    }
    if (Object.prototype.hasOwnProperty.call(payload, 'floatingPreview')) {
      state.floatingPreview = normalizeFloatingPreviewState(
        payload.floatingPreview,
        state.floatingPreview
      );
    } else {
      state.floatingPreview = normalizeFloatingPreviewState(
        state.floatingPreview,
        FLOATING_PREVIEW_DEFAULT_STATE
      );
    }
    if (Object.prototype.hasOwnProperty.call(payload, 'localViewportCanvases')) {
      localViewportCanvasState = normalizeLocalViewportCanvasState(
        payload.localViewportCanvases,
        localViewportCanvasState
      );
    } else {
      localViewportCanvasState = normalizeLocalViewportCanvasState(
        localViewportCanvasState,
        LOCAL_VIEWPORT_CANVAS_DEFAULT_STATE
      );
    }
    requestLocalViewportCanvasLayoutReset({ clearStored: true });
    localLayerVisibilityById = deserializeLocalLayerVisibilityMap(
      payload.layerVisibilityById,
      localLayerVisibilityById
    );
    applyLocalLayerVisibilityToState();
    localLayerPreviewOpacityById = deserializeLocalLayerPreviewOpacityMap(
      payload.layerPreviewOpacityById,
      localLayerPreviewOpacityById
    );
    applyLocalLayerPreviewOpacityToState();
    if (typeof payload.showChecker === 'boolean') {
      state.showChecker = payload.showChecker;
    }
    if (typeof payload.danmakuEnabled === 'boolean') {
      state.danmakuEnabled = payload.danmakuEnabled;
    }
    state.dualLeftRail = false;
    leftDualSizing.tools = LEFT_DUAL_MIN_COLUMN_WIDTH;
    if (Number.isFinite(payload.leftUnifiedToolsRatio)) {
      leftUnifiedSplitSizing.ratio = normalizeLeftUnifiedToolsRatio(
        payload.leftUnifiedToolsRatio,
        leftUnifiedSplitSizing.ratio
      );
    } else {
      leftUnifiedSplitSizing.ratio = normalizeLeftUnifiedToolsRatio(
        leftUnifiedSplitSizing.ratio,
        LEFT_UNIFIED_TOOLS_RATIO_DEFAULT
      );
    }
    if (Object.prototype.hasOwnProperty.call(payload, 'onionSkin')) {
      state.onionSkin = normalizeOnionSkinState(payload.onionSkin);
    }
    setVirtualCursorButtonScale(state.virtualCursorButtonScale, { persist: false, clampPosition: false });
    state.colorMode = normalizeColorMode(payload.colorMode, state.colorMode);
    if (Object.prototype.hasOwnProperty.call(payload, 'activeRgb')) {
      state.activeRgb = normalizeColorValue(payload.activeRgb);
    } else {
      state.activeRgb = normalizeColorValue(state.activeRgb);
    }
    if (Number.isFinite(payload.paletteIndex)) {
      state.activePaletteIndex = normalizePaletteIndex(payload.paletteIndex, state.activePaletteIndex);
    }
    if (Number.isFinite(payload.secondaryPaletteIndex)) {
      state.secondaryPaletteIndex = normalizePaletteIndex(
        payload.secondaryPaletteIndex,
        state.activePaletteIndex
      );
    } else {
      state.secondaryPaletteIndex = normalizePaletteIndex(
        state.secondaryPaletteIndex,
        state.activePaletteIndex
      );
    }
    if (!Object.prototype.hasOwnProperty.call(payload, 'activeRgb')) {
      const fallbackPaletteColor = state.palette[state.activePaletteIndex] || state.activeRgb;
      state.activeRgb = normalizeColorValue(fallbackPaletteColor);
    }
    if (Number.isFinite(payload.activeFrame)) {
      state.activeFrame = clamp(Math.round(payload.activeFrame), 0, state.frames.length - 1);
    }
    const frame = state.frames[state.activeFrame];
    if (frame && frame.layers && frame.layers.length) {
      const preferredLayer = typeof payload.activeLayer === 'string' ? payload.activeLayer : null;
      const fallbackLayer = frame.layers.find(layer => layer.id === preferredLayer);
      state.activeLayer = fallbackLayer ? fallbackLayer.id : frame.layers[frame.layers.length - 1].id;
    }
    if (!state.lastGroupTool) {
      state.lastGroupTool = { ...DEFAULT_GROUP_TOOL };
    }
    state.tool = normalizeToolId(state.tool, 'pen');
    if (!TOOL_GROUPS[state.activeToolGroup]?.tools?.includes(state.tool)) {
      state.activeToolGroup = TOOL_TO_GROUP[state.tool] || 'pen';
    } else {
      state.activeToolGroup = state.activeToolGroup || TOOL_TO_GROUP[state.tool] || 'pen';
    }
    if (typeof payload.documentName === 'string') {
      state.documentName = normalizeDocumentName(payload.documentName);
    }
    if (typeof payload.pixfindMode === 'boolean') {
      pixfindModeEnabled = payload.pixfindMode;
    }
    if (typeof payload.pixfindModeFirstEnableConfirmed === 'boolean') {
      pixfindModeFirstEnableConfirmed = payload.pixfindModeFirstEnableConfirmed;
    } else if (pixfindModeEnabled) {
      pixfindModeFirstEnableConfirmed = true;
    }
    if (typeof payload.exportIncludeOriginalSize === 'boolean') {
      exportIncludeOriginalSize = payload.exportIncludeOriginalSize;
    }
    if (typeof payload.exportSaveProjectCompanion === 'boolean') {
      exportSaveProjectCompanion = payload.exportSaveProjectCompanion;
    }
    if (typeof payload.exportContestPostAfterSave === 'boolean') {
      exportContestPostAfterSave = payload.exportContestPostAfterSave;
    }
    if (typeof payload.exportSaveSpriteMapCompanion === 'boolean') {
      exportSaveSpriteMapCompanion = payload.exportSaveSpriteMapCompanion;
    }
    if (typeof payload.exportColorSpritesEnabled === 'boolean') {
      exportColorSpritesEnabled = payload.exportColorSpritesEnabled;
    }
    if (Number.isFinite(payload.exportGridTileWidth)) {
      exportGridTileWidth = normalizeExportGridTileSize(payload.exportGridTileWidth, exportGridTileWidth);
    }
    if (Number.isFinite(payload.exportGridTileHeight)) {
      exportGridTileHeight = normalizeExportGridTileSize(payload.exportGridTileHeight, exportGridTileHeight);
    }
    if (typeof payload.timelapseEnabled === 'boolean') {
      timelapseState.enabled = payload.timelapseEnabled;
    }
    if (Number.isFinite(payload.timelapseFps)) {
      timelapseState.fps = normalizeTimelapseFps(payload.timelapseFps);
    }
    if (Number.isFinite(payload.multiMaxGuests)) {
      multiState.maxGuests = normalizeMultiMaxGuests(payload.multiMaxGuests, multiState.maxGuests);
    }
    if (typeof payload.multiRoomVisibility === 'string') {
      multiState.roomVisibility = normalizeMultiRoomVisibility(
        payload.multiRoomVisibility,
        multiState.roomVisibility
      );
    }
    if (typeof payload.multiJoinPolicy === 'string') {
      multiState.joinPolicy = normalizeMultiJoinPolicy(
        payload.multiJoinPolicy,
        multiState.joinPolicy
      );
    }
    if (typeof payload.multiParticipantFreeCellMove === 'boolean') {
      multiState.participantFreeCellMove = payload.multiParticipantFreeCellMove;
    }
    if (typeof payload.multiMasterOpsMode === 'boolean') {
      multiState.masterOpsMode = payload.multiMasterOpsMode;
    }
    if (typeof payload.multiExportPermission === 'string') {
      multiState.exportPermission = normalizeMultiExportPermission(
        payload.multiExportPermission,
        multiState.exportPermission
      );
    }
    if (state.showVirtualCursor && !virtualCursor) {
      virtualCursor = createInitialVirtualCursor();
    }
    if (!state.showVirtualCursor) {
      releaseVirtualCursorPointer();
    }
    updatePixfindModeUI();
    updateFloatingDrawButtonEnabledState();
    refreshViewportCursorStyle();
  }

  function normalizeMultiMaxGuests(value, fallback = MULTI_DEFAULT_GUEST_LIMIT, maxLimit = MULTI_GUEST_LIMIT_MAX) {
    const safeMaxLimit = clamp(
      Math.round(Number(maxLimit) || MULTI_GUEST_LIMIT_MAX),
      MULTI_GUEST_LIMIT_MIN,
      MULTI_GUEST_LIMIT_MAX
    );
    const numeric = Math.round(Number(value));
    if (Number.isFinite(numeric)) {
      return clamp(numeric, MULTI_GUEST_LIMIT_MIN, safeMaxLimit);
    }
    const fallbackNumeric = Math.round(Number(fallback));
    if (Number.isFinite(fallbackNumeric)) {
      return clamp(fallbackNumeric, MULTI_GUEST_LIMIT_MIN, safeMaxLimit);
    }
    return clamp(MULTI_DEFAULT_GUEST_LIMIT, MULTI_GUEST_LIMIT_MIN, safeMaxLimit);
  }

  function normalizeMultiParticipantFreeCellMove(value, fallback = MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE) {
    if (typeof value === 'boolean') {
      return value;
    }
    return Boolean(fallback);
  }

  function normalizeMultiExportPermission(value, fallback = MULTI_DEFAULT_EXPORT_PERMISSION) {
    if (value === MULTI_EXPORT_PERMISSION_MASTER) {
      return MULTI_EXPORT_PERMISSION_MASTER;
    }
    if (value === MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST) {
      return MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST;
    }
    if (value === MULTI_EXPORT_PERMISSION_ALL) {
      return MULTI_EXPORT_PERMISSION_ALL;
    }
    if (fallback === MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST || fallback === MULTI_EXPORT_PERMISSION_ALL) {
      return fallback;
    }
    return MULTI_EXPORT_PERMISSION_MASTER;
  }

  function normalizeMultiJoinPolicy(value, fallback = MULTI_DEFAULT_JOIN_POLICY) {
    if (value === MULTI_JOIN_POLICY_OPEN) {
      return MULTI_JOIN_POLICY_OPEN;
    }
    if (value === MULTI_JOIN_POLICY_APPROVAL) {
      return MULTI_JOIN_POLICY_APPROVAL;
    }
    return fallback === MULTI_JOIN_POLICY_OPEN
      ? MULTI_JOIN_POLICY_OPEN
      : MULTI_JOIN_POLICY_APPROVAL;
  }

  function getMultiJoinPolicyLabel(value = multiState.joinPolicy) {
    return normalizeMultiJoinPolicy(value, MULTI_DEFAULT_JOIN_POLICY) === MULTI_JOIN_POLICY_OPEN
      ? localizeText('自動参加', 'Auto Join')
      : localizeText('承認制', 'Approval');
  }

  function applyMultiMasterPreset(preset = 'friends') {
    if (!isMultiMasterConfigMode()) {
      return false;
    }
    const normalizedPreset = preset === 'stream' ? 'stream' : 'friends';
    let changed = false;
    if (normalizedPreset === 'friends') {
      const nextJoinPolicy = MULTI_JOIN_POLICY_OPEN;
      const nextRoomVisibility = MULTI_ROOM_VISIBILITY_PRIVATE;
      const nextExportPermission = MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST;
      if (multiState.joinPolicy !== nextJoinPolicy) {
        multiState.joinPolicy = nextJoinPolicy;
        changed = true;
      }
      if (multiState.roomVisibility !== nextRoomVisibility) {
        multiState.roomVisibility = nextRoomVisibility;
        changed = true;
      }
      if (multiState.exportPermission !== nextExportPermission) {
        multiState.exportPermission = nextExportPermission;
        changed = true;
      }
    } else {
      const nextJoinPolicy = MULTI_JOIN_POLICY_APPROVAL;
      const nextRoomVisibility = MULTI_ROOM_VISIBILITY_PRIVATE;
      const nextExportPermission = MULTI_EXPORT_PERMISSION_MASTER;
      if (multiState.joinPolicy !== nextJoinPolicy) {
        multiState.joinPolicy = nextJoinPolicy;
        changed = true;
      }
      if (multiState.roomVisibility !== nextRoomVisibility) {
        multiState.roomVisibility = nextRoomVisibility;
        changed = true;
      }
      if (multiState.exportPermission !== nextExportPermission) {
        multiState.exportPermission = nextExportPermission;
        changed = true;
      }
      if (multiState.masterOpsMode) {
        multiState.masterOpsMode = false;
        changed = true;
      }
    }
    if (changed) {
      scheduleSessionPersist({ includeSnapshots: false });
      if (isMultiMasterMode()) {
        scheduleMultiSessionStateBroadcast({ immediate: true });
        scheduleMultiPublicLobbyRoomSync({ immediate: true });
      }
    }
    setMultiStatus(
      normalizedPreset === 'friends'
        ? 'クイック設定: 友達向け（自動参加）を適用しました'
        : 'クイック設定: 配信向け（承認制）を適用しました',
      'success'
    );
    syncMultiControls();
    return true;
  }

  function getMultiExportPermissionLabel(permission = multiState.exportPermission) {
    const normalized = normalizeMultiExportPermission(permission, MULTI_DEFAULT_EXPORT_PERMISSION);
    if (normalized === MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST) {
      return localizeText('マスター + 参加者', 'Master + Participants');
    }
    if (normalized === MULTI_EXPORT_PERMISSION_ALL) {
      return localizeText('全員', 'Everyone');
    }
    return localizeText('マスターのみ', 'Master Only');
  }

  function normalizeMultiRoomVisibility(value, fallback = MULTI_DEFAULT_ROOM_VISIBILITY) {
    const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
    if (normalized === MULTI_ROOM_VISIBILITY_PUBLIC) {
      return MULTI_ROOM_VISIBILITY_PUBLIC;
    }
    if (normalized === MULTI_ROOM_VISIBILITY_PRIVATE || normalized === 'shared' || normalized === 'limited') {
      return MULTI_ROOM_VISIBILITY_PRIVATE;
    }
    return fallback === MULTI_ROOM_VISIBILITY_PUBLIC
      ? MULTI_ROOM_VISIBILITY_PUBLIC
      : MULTI_ROOM_VISIBILITY_PRIVATE;
  }

  function getMultiRoomVisibilityLabel(value = multiState.roomVisibility) {
    return normalizeMultiRoomVisibility(value, MULTI_DEFAULT_ROOM_VISIBILITY) === MULTI_ROOM_VISIBILITY_PUBLIC
      ? localizeText('公開', 'Public')
      : localizeText('非公開', 'Private');
  }

  function isMultiRoomPublic() {
    return normalizeMultiRoomVisibility(
      multiState.roomVisibility,
      MULTI_DEFAULT_ROOM_VISIBILITY
    ) === MULTI_ROOM_VISIBILITY_PUBLIC;
  }

  function shouldSyncMultiPublicLobbyRoom() {
    return false;
  }

  function clearMultiPublicLobbySyncTimer() {
    if (multiState.publicLobbySyncTimer !== null) {
      window.clearTimeout(multiState.publicLobbySyncTimer);
      multiState.publicLobbySyncTimer = null;
    }
  }

  async function disconnectMultiPublicLobbyChannel() {
    clearMultiPublicLobbySyncTimer();
    const lobbyChannel = multiState.publicLobbyChannel;
    multiState.publicLobbyChannel = null;
    multiState.publicLobbySyncInFlight = false;
    multiState.publicLobbyThumbnailDirty = false;
    multiState.publicLobbyThumbnailDataUrl = '';
    multiState.publicLobbyThumbnailUpdatedAt = 0;
    if (!lobbyChannel) {
      return;
    }
    try {
      if (typeof lobbyChannel.untrack === 'function') {
        await lobbyChannel.untrack();
      }
    } catch (_error) {
      // Ignore untrack failures.
    }
    try {
      if (typeof lobbyChannel.unsubscribe === 'function') {
        await lobbyChannel.unsubscribe();
      }
    } catch (_error) {
      // Ignore unsubscribe failures.
    }
  }

  async function ensureMultiPublicLobbyChannel() {
    return null;
  }

  function getMultiPresenceParticipantCounts() {
    return { guestCount: 0, spectatorCount: 0, totalCount: 0 };
  }

  function createMultiPublicRoomThumbnailDataUrl() {
    return '';
  }

  function markMultiPublicLobbyThumbnailDirty() {
    multiState.publicLobbyThumbnailDirty = false;
  }

  function getMultiPublicRoomThumbnailDataUrl() {
    return '';
  }

  function buildMultiPublicLobbyPresencePayload() {
    return null;
  }

  async function syncMultiPublicLobbyRoomNow() {
    await disconnectMultiPublicLobbyChannel();
    return false;
  }

  function scheduleMultiPublicLobbyRoomSync() {
    disconnectMultiPublicLobbyChannel();
  }

  function canCurrentClientExportProject(format = 'png') {
    const normalizedFormat = normalizeExportFormat(format);
    if (!multiState.connected) {
      return true;
    }
    if (isSharedProjectCollaborativeMode()) {
      return true;
    }
    if (normalizedFormat === 'project') {
      return isMultiMasterMode();
    }
    const permission = normalizeMultiExportPermission(
      multiState.exportPermission,
      MULTI_DEFAULT_EXPORT_PERMISSION
    );
    const role = multiState.role === 'master'
      ? 'master'
      : (multiState.role === 'guest'
        ? 'guest'
        : (multiState.role === 'spectator' ? 'spectator' : 'none'));
    if (role === 'master') {
      return true;
    }
    if (role === 'guest') {
      return permission === MULTI_EXPORT_PERMISSION_MASTER_AND_GUEST
        || permission === MULTI_EXPORT_PERMISSION_ALL;
    }
    if (role === 'spectator') {
      return permission === MULTI_EXPORT_PERMISSION_ALL;
    }
    return true;
  }

  function getMultiExportDisabledReason(format = 'png') {
    const normalizedFormat = normalizeExportFormat(format);
    if (!multiState.connected || canCurrentClientExportProject(normalizedFormat)) {
      return '';
    }
    if (normalizedFormat === 'project') {
      if (!isMultiMasterMode()) {
        return 'プロジェクト保存はマスターのみ利用できます';
      }
    }
    return `出力は${getMultiExportPermissionLabel()}に制限されています`;
  }

  function ensureCurrentClientCanExportProject({ announce = true, format = 'png' } = {}) {
    const reason = getExportDisabledReason(format);
    if (!reason) {
      return true;
    }
    if (announce) {
      setMultiStatus(`共有モード: ${reason}`, 'warn');
      updateAutosaveStatus(reason, 'warn');
    }
    return false;
  }

  function isMultiGuestLimitReached(ignoreClientId = '') {
    const maxGuests = normalizeMultiMaxGuests(multiState.maxGuests, MULTI_DEFAULT_GUEST_LIMIT);
    let guestCount = 0;
    multiState.assignments.forEach((entry, clientId) => {
      if (!entry || entry.role !== 'guest') {
        return;
      }
      if (ignoreClientId && clientId === ignoreClientId) {
        return;
      }
      if (isMultiClientBlocked(clientId)) {
        return;
      }
      guestCount += 1;
    });
    return guestCount >= maxGuests;
  }

  function getAssignedGuestCount() {
    let guestCount = 0;
    multiState.assignments.forEach((entry, clientId) => {
      if (!entry || entry.role !== 'guest') {
        return;
      }
      if (isMultiClientBlocked(clientId)) {
        return;
      }
      guestCount += 1;
    });
    return guestCount;
  }

  function normalizeMultiProjectKey(value) {
    if (typeof value !== 'string') {
      return '';
    }
    return value
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9_-]/g, '')
      .slice(0, 40);
  }

  const multiInviteUtils = window.PiXiEEDrawModules?.multiInviteUtils?.createMultiInviteUtils?.({
    normalizeMultiProjectKey,
    canUseSessionStorage,
    getCurrentSharedRecentProjectEntry,
    getCurrentMultiProjectKey: () => multiState.projectKey,
    MULTI_INVITE_QUERY_FLAG,
    MULTI_INVITE_QUERY_KEY,
    MULTI_INVITE_QUERY_TOKEN,
    MULTI_INVITE_QUERY_AUTO_JOIN,
    MULTI_INVITE_QUERY_ROLE,
    MULTI_PENDING_INVITE_STORAGE_KEY,
    MULTI_PENDING_INVITE_TTL_MS,
  }) || {};
  const {
    parseMultiProjectAccessInput,
    resolveMultiInviteDefaultRole,
    buildMultiInviteUrl,
    clearMultiInviteQueryParamsFromUrl,
    clearPendingSharedInvite,
    storePendingSharedInvite,
    readPendingSharedInvite,
    readMultiInviteFromUrl,
  } = multiInviteUtils;

  function readCurrentMultiProjectAccessInput() {
    if (dom.controls.multiJoinProjectKey instanceof HTMLInputElement) {
      const parsed = parseMultiProjectAccessInput(dom.controls.multiJoinProjectKey.value);
      if (parsed.projectKey || parsed.inviteToken) {
        return parsed;
      }
    }
    if (dom.controls.multiProjectKey instanceof HTMLInputElement) {
      const parsed = parseMultiProjectAccessInput(dom.controls.multiProjectKey.value);
      if (parsed.projectKey || parsed.inviteToken) {
        return parsed;
      }
    }
    const fallbackProjectKey = normalizeMultiProjectKey(multiState.projectKey || '');
    const fallbackEntry = getCurrentSharedRecentProjectEntry(fallbackProjectKey);
    return {
      raw: fallbackProjectKey,
      projectKey: fallbackProjectKey,
      inviteToken: typeof fallbackEntry?.sharedProjectInviteToken === 'string'
        ? fallbackEntry.sharedProjectInviteToken.trim()
        : '',
    };
  }

  function readMultiJoinProjectAccessInputOnly() {
    if (!(dom.controls.multiJoinProjectKey instanceof HTMLInputElement)) {
      return {
        raw: '',
        projectKey: '',
        inviteToken: '',
      };
    }
    return parseMultiProjectAccessInput(dom.controls.multiJoinProjectKey.value);
  }

  function getMultiProjectKeyInputElements() {
    const inputs = [];
    if (dom.controls.multiJoinProjectKey instanceof HTMLInputElement) {
      inputs.push(dom.controls.multiJoinProjectKey);
    }
    if (
      dom.controls.multiProjectKey instanceof HTMLInputElement
      && dom.controls.multiProjectKey !== dom.controls.multiJoinProjectKey
    ) {
      inputs.push(dom.controls.multiProjectKey);
    }
    return inputs;
  }

  function readCurrentMultiProjectKey() {
    const parsed = readCurrentMultiProjectAccessInput();
    if (parsed.projectKey) {
      return parsed.projectKey;
    }
    return normalizeMultiProjectKey(multiState.projectKey || '');
  }

  function syncMultiProjectKeyInputValues(projectKey, { preserveFocused = true } = {}) {
    const normalized = normalizeMultiProjectKey(projectKey || '');
    const activeElement = document.activeElement;
    getMultiProjectKeyInputElements().forEach(input => {
      if (preserveFocused && input === activeElement) {
        return;
      }
      input.value = normalized;
    });
  }

  function isMultiAssignedCellRestrictedEditorMode() {
    if (isSharedProjectCollaborativeMode()) {
      return false;
    }
    return isMultiGuestMode();
  }

  function maybeApplyInviteAutoJoin() {
    if (multiInviteAutoJoinHandled) {
      return false;
    }
    multiInviteAutoJoinHandled = true;
    if (!SHARED_PROJECTS_ENABLED) {
      clearPendingSharedInvite();
      clearMultiInviteQueryParamsFromUrl();
      return false;
    }
    const invite = readMultiInviteFromUrl();
    if (!invite) {
      return false;
    }
    const normalizedInviteProjectKey = normalizeMultiProjectKey(invite.projectKey || '');
    const requestedRole = invite.role === 'master' || invite.role === 'guest' || invite.role === 'spectator'
      ? invite.role
      : 'guest';
    if (!normalizedInviteProjectKey && !invite.inviteToken) {
      return false;
    }
    syncMultiControls();
    setMultiStatus(
      localizeText(
        `共有プロジェクトを開いています (${normalizedInviteProjectKey})`,
        `Opening shared project (${normalizedInviteProjectKey})`
      ),
      'info'
    );
    const openSharedInviteProject = async () => {
      if (
        normalizedInviteProjectKey
        && (
          activeSharedProjectCanonicalOpenKey === normalizedInviteProjectKey
          || (
            normalizeMultiProjectKey(activeSharedProjectKey || '') === normalizedInviteProjectKey
            && activeSharedProjectDocumentLoaded
            && isCurrentProjectSharedEntry()
          )
        )
      ) {
        clearPendingSharedInvite();
        return true;
      }
      let prefetchedInviteProject = null;
      if ((!accountState.isLoggedIn || accountState.isAnonymous) && invite.inviteToken) {
        const inviteProject = await fetchSharedProjectRecordByInviteToken(invite.inviteToken);
        prefetchedInviteProject = inviteProject;
        if (!inviteProject?.project_key || inviteProject.visibility !== MULTI_ROOM_VISIBILITY_PUBLIC) {
          storePendingSharedInvite({
            inviteToken: invite.inviteToken || '',
            projectKey: normalizedInviteProjectKey,
            requestedRole,
            autoJoin: invite.autoJoin !== false,
            source: 'url-invite',
          });
          setMultiStatus(
            localizeText(
              '限定プロジェクトを開くにはログインしてください。',
              'Sign in to open this limited project.'
            ),
            'warn'
          );
          openLoginPromptDialog();
          return false;
        }
        if (inviteProject?.project_key && !isBrokenSharedInviteBinding(inviteProject, {
          expectedInviteToken: invite.inviteToken,
          expectedProjectKey: normalizedInviteProjectKey,
        })) {
          await upsertSharedRecentProjectEntry({
            projectKey: normalizeMultiProjectKey(inviteProject.project_key),
            projectId: inviteProject.id || '',
            inviteToken: inviteProject.invite_token || invite.inviteToken,
            visibility: inviteProject.visibility || 'shared',
            name: createSharedProjectSnapshotTitle(inviteProject.title || normalizedInviteProjectKey || DEFAULT_DOCUMENT_NAME),
            fileName: normalizeDocumentName(`${createSharedProjectSnapshotTitle(inviteProject.title || normalizedInviteProjectKey || DEFAULT_DOCUMENT_NAME)}.pixiedraw`),
            thumbnail: null,
            roleHint: 'guest',
            membershipRole: inviteProject.membership_role || '',
            ownerUserId: inviteProject.owner_user_id || '',
            autoJoin: invite.autoJoin !== false,
            revision: Math.max(0, Math.round(Number(inviteProject.latest_revision) || 0)),
            structureRevision: Math.max(0, Math.round(Number(inviteProject.latest_structure_revision) || 0)),
          });
        }
      }
      const sessionReady = (!accountState.isLoggedIn || accountState.isAnonymous)
        ? await ensurePublicSharedProjectUrlSession(prefetchedInviteProject)
        : await ensureSharedProjectAuthenticatedStart({ requireLogin: true });
      if (!sessionReady) {
        storePendingSharedInvite({
          inviteToken: invite.inviteToken || '',
          projectKey: normalizedInviteProjectKey,
          requestedRole,
          autoJoin: invite.autoJoin !== false,
          source: 'url-invite',
        });
        return false;
      }
      return await openSharedProjectCanonical({
        inviteToken: invite.inviteToken || '',
        projectKey: normalizedInviteProjectKey,
        requestedRole,
        autoJoin: invite.autoJoin !== false,
        reason: 'url-invite',
        hideStartup: true,
        silent: true,
        successMessage: localizeText(
          '共有URLを読み込みました。共有プロジェクトを開いています。',
          'Shared URL loaded. Opening shared project.'
        ),
      });
    };
    window.setTimeout(() => {
      openSharedInviteProject()
        .then(async result => {
          if (result) {
            clearPendingSharedInvite();
            clearMultiInviteQueryParamsFromUrl();
          } else {
            if (!readPendingSharedInvite()) {
              const failureMessage = localizeText(
                '共有URLを開けませんでした。',
                'Failed to open shared URL.'
              );
              const dialogShown = await maybeOpenSharedInviteFailureDialog({
                reason: failureMessage,
              });
              setMultiStatus(failureMessage, 'error');
              if (dialogShown) {
                updateAutosaveStatus(
                  localizeText(
                    '端末内に通常プロジェクトがないため、共有リンクを確認してください。',
                    'There are no local projects on this device, so check the shared link.'
                  ),
                  'error'
                );
              }
            }
          }
        })
        .catch(async error => {
          console.warn('Failed to open shared invite project', error);
          const failureMessage = localizeText(
            '共有URLを開けませんでした。',
            'Failed to open shared URL.'
          );
          await maybeOpenSharedInviteFailureDialog({
            reason: failureMessage,
            detail: localizeText(
              '共有リンクまたはネットワーク状態を確認してからもう一度開いてください。',
              'Check the shared link or network connection, then try opening it again.'
            ),
          });
          setMultiStatus(failureMessage, 'error');
        });
    }, 100);
    return true;
  }

