  async function openSharedProjectFromInput() {
    if (!ensureInternetConnectedForAction('共有プロジェクトを開く', 'Opening a shared project')) {
      return false;
    }
    if (isSharedProjectsBlockedByRuntime()) {
      showSharedRuntimeBlockedStatus();
      return false;
    }
    await initPixieedAccount();
    await ensureNoLegacyMultiSessionForSharedProject();
    const access = readMultiJoinProjectAccessInputOnly();
    if (!access.projectKey && !access.inviteToken) {
      setMultiStatus(
        localizeText('共有リンクまたは招待コードを入力してください', 'Paste an invite link or invite code'),
        'warn'
      );
      return false;
    }
    if (!(await ensureSharedProjectAuthenticatedStart({ requireLogin: true }))) {
      storePendingSharedInvite({
        inviteToken: access.inviteToken || '',
        projectKey: access.projectKey || '',
        requestedRole: 'guest',
        autoJoin: false,
        source: 'manual-open',
      });
      return false;
    }
    const opened = await openSharedProjectCanonical({
      inviteToken: access.inviteToken || '',
      projectKey: access.projectKey || '',
      requestedRole: 'guest',
      autoJoin: false,
      reason: 'manual-open',
    });
    if (opened) {
      clearPendingSharedInvite();
    }
    return opened;
  }

  async function openSharedProjectFromHomeInput() {
    const homeInput = dom.controls.projectHomeJoinProjectKey;
    const panelInput = dom.controls.multiJoinProjectKey;
    if (!(homeInput instanceof HTMLInputElement) || !(panelInput instanceof HTMLInputElement)) {
      return false;
    }
    const rawValue = (homeInput.value || '').trim();
    if (!rawValue) {
      setMultiStatus(localizeText('コードを入力してください', 'Enter a code'), 'warn');
      return false;
    }
    panelInput.value = rawValue;
    return await openSharedProjectFromInput();
  }

  async function disableSharedProjectMode() {
    if (multiState.connected || multiState.connecting) {
      disconnectMultiSession({ silent: false });
    }
    clearActiveSharedProjectSession();
    multiState.projectKey = '';
    syncMultiProjectKeyInputValues('', { preserveFocused: false });
    syncMultiControls();
    setMultiStatus(
      localizeText('共有モードをOFFにしました', 'Shared mode turned off'),
      'info'
    );
    return true;
  }

  function readStoredMultiProjectKey() {
    if (!canUseSessionStorage) {
      return '';
    }
    try {
      return normalizeMultiProjectKey(window.localStorage.getItem(getScopedStorageKey(MULTI_PROJECT_KEY_STORAGE_KEY)) || '');
    } catch (error) {
      return '';
    }
  }

  function storeMultiProjectKey(projectKey) {
    const normalized = normalizeMultiProjectKey(projectKey);
    multiState.projectKey = normalized;
    if (normalized && (!Array.isArray(multiState.comments) || multiState.comments.length === 0)) {
      restoreMultiCommentsForProject(normalized);
    }
    if (!canUseSessionStorage) {
      return;
    }
    try {
      if (normalized) {
        window.localStorage.setItem(getScopedStorageKey(MULTI_PROJECT_KEY_STORAGE_KEY), normalized);
      } else {
        window.localStorage.removeItem(getScopedStorageKey(MULTI_PROJECT_KEY_STORAGE_KEY));
      }
    } catch (error) {
      // Ignore storage errors.
    }
  }

  function clearStoredMultiResumeSession() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.sessionStorage.removeItem(getScopedStorageKey(MULTI_RESUME_STORAGE_KEY));
    } catch (error) {
      // Ignore storage errors.
    }
  }

  function storePendingMultiResumeSession() {
    if (prefersSharedProjectFlow()) {
      clearStoredMultiResumeSession();
      return;
    }
    if (!canUseSessionStorage) {
      return;
    }
    const role = multiState.role === 'master'
      ? 'master'
      : (multiState.role === 'guest' ? 'guest' : (multiState.role === 'spectator' ? 'spectator' : 'none'));
    const projectKey = normalizeMultiProjectKey(multiState.projectKey || '');
    if (!multiState.connected || role === 'none' || !projectKey) {
      clearStoredMultiResumeSession();
      return;
    }
    const payload = {
      projectKey,
      role,
      at: Date.now(),
      assignments: role === 'master' ? serializeMultiAssignments() : [],
      blockedClientIds: role === 'master' ? serializeMultiBlockedClientIds() : [],
      maxGuests: role === 'master'
        ? normalizeMultiMaxGuests(multiState.maxGuests, MULTI_DEFAULT_GUEST_LIMIT)
        : MULTI_DEFAULT_GUEST_LIMIT,
      roomVisibility: role === 'master'
        ? normalizeMultiRoomVisibility(
          multiState.roomVisibility,
          MULTI_DEFAULT_ROOM_VISIBILITY
        )
        : MULTI_DEFAULT_ROOM_VISIBILITY,
      joinPolicy: role === 'master'
        ? normalizeMultiJoinPolicy(
          multiState.joinPolicy,
          MULTI_DEFAULT_JOIN_POLICY
        )
        : MULTI_DEFAULT_JOIN_POLICY,
      participantFreeCellMove: role === 'master'
        ? normalizeMultiParticipantFreeCellMove(
          multiState.participantFreeCellMove,
          MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE
        )
        : MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE,
      exportPermission: role === 'master'
        ? normalizeMultiExportPermission(multiState.exportPermission, MULTI_DEFAULT_EXPORT_PERMISSION)
        : MULTI_DEFAULT_EXPORT_PERMISSION,
    };
    try {
      window.sessionStorage.setItem(getScopedStorageKey(MULTI_RESUME_STORAGE_KEY), JSON.stringify(payload));
    } catch (error) {
      // Ignore storage errors.
    }
  }

  function readStoredMultiResumeSession() {
    if (!canUseSessionStorage) {
      return null;
    }
    let parsed = null;
    try {
      const raw = window.sessionStorage.getItem(getScopedStorageKey(MULTI_RESUME_STORAGE_KEY));
      if (!raw) {
        return null;
      }
      parsed = JSON.parse(raw);
    } catch (error) {
      clearStoredMultiResumeSession();
      return null;
    }
    if (!parsed || typeof parsed !== 'object') {
      clearStoredMultiResumeSession();
      return null;
    }
    const projectKey = normalizeMultiProjectKey(parsed.projectKey);
    const role = parsed.role === 'master'
      ? 'master'
      : (parsed.role === 'guest' ? 'guest' : (parsed.role === 'spectator' ? 'spectator' : 'none'));
    const timestamp = Number(parsed.at);
    const age = Date.now() - timestamp;
    if (!projectKey || role === 'none' || !Number.isFinite(timestamp) || age < 0 || age > MULTI_RESUME_MAX_AGE_MS) {
      clearStoredMultiResumeSession();
      return null;
    }
    const assignments = role === 'master' && Array.isArray(parsed.assignments)
      ? parsed.assignments
      : [];
    const blockedClientIds = role === 'master' && Array.isArray(parsed.blockedClientIds)
      ? parsed.blockedClientIds
      : [];
    const maxGuests = role === 'master'
      ? normalizeMultiMaxGuests(parsed.maxGuests, MULTI_DEFAULT_GUEST_LIMIT)
      : MULTI_DEFAULT_GUEST_LIMIT;
    const roomVisibility = role === 'master'
      ? normalizeMultiRoomVisibility(parsed.roomVisibility, MULTI_DEFAULT_ROOM_VISIBILITY)
      : MULTI_DEFAULT_ROOM_VISIBILITY;
    const joinPolicy = role === 'master'
      ? normalizeMultiJoinPolicy(parsed.joinPolicy, MULTI_DEFAULT_JOIN_POLICY)
      : MULTI_DEFAULT_JOIN_POLICY;
    const participantFreeCellMove = role === 'master'
      ? normalizeMultiParticipantFreeCellMove(
        parsed.participantFreeCellMove,
        MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE
      )
      : MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE;
    const exportPermission = role === 'master'
      ? normalizeMultiExportPermission(parsed.exportPermission, MULTI_DEFAULT_EXPORT_PERMISSION)
      : MULTI_DEFAULT_EXPORT_PERMISSION;
    return {
      projectKey,
      role,
      assignments,
      blockedClientIds,
      maxGuests,
      roomVisibility,
      joinPolicy,
      participantFreeCellMove,
      exportPermission,
    };
  }

  function maybeAutoResumeMultiSession() {
    if (multiAutoResumeAttempted || multiState.connected || multiState.connecting) {
      return;
    }
    multiAutoResumeAttempted = true;
    const pending = readStoredMultiResumeSession();
    if (!pending) {
      return;
    }
    if (prefersSharedProjectFlow()) {
      clearStoredMultiResumeSession();
      return;
    }
    clearStoredMultiResumeSession();
    storeMultiProjectKey(pending.projectKey);
    syncMultiProjectKeyInputValues(pending.projectKey, { preserveFocused: false });
    setMultiDesiredRole(pending.role);
    setMultiUiView(pending.role);
    multiState.resumeAssignments = pending.role === 'master' && Array.isArray(pending.assignments)
      ? pending.assignments
      : null;
    multiState.resumeBlockedClientIds = pending.role === 'master' && Array.isArray(pending.blockedClientIds)
      ? pending.blockedClientIds
      : null;
    multiState.resumeMaxGuests = pending.role === 'master'
      ? normalizeMultiMaxGuests(pending.maxGuests, multiState.maxGuests)
      : null;
    multiState.resumeRoomVisibility = pending.role === 'master'
      ? normalizeMultiRoomVisibility(pending.roomVisibility, multiState.roomVisibility)
      : null;
    multiState.resumeJoinPolicy = pending.role === 'master'
      ? normalizeMultiJoinPolicy(pending.joinPolicy, multiState.joinPolicy)
      : null;
    multiState.resumeParticipantFreeCellMove = pending.role === 'master'
      ? normalizeMultiParticipantFreeCellMove(pending.participantFreeCellMove, multiState.participantFreeCellMove)
      : null;
    multiState.resumeExportPermission = pending.role === 'master'
      ? normalizeMultiExportPermission(pending.exportPermission, multiState.exportPermission)
      : null;
    if (pending.role === 'master') {
      multiState.maxGuests = normalizeMultiMaxGuests(pending.maxGuests, multiState.maxGuests);
      multiState.roomVisibility = normalizeMultiRoomVisibility(
        pending.roomVisibility,
        multiState.roomVisibility
      );
      multiState.joinPolicy = normalizeMultiJoinPolicy(
        pending.joinPolicy,
        multiState.joinPolicy
      );
      multiState.participantFreeCellMove = normalizeMultiParticipantFreeCellMove(
        pending.participantFreeCellMove,
        multiState.participantFreeCellMove
      );
      multiState.exportPermission = normalizeMultiExportPermission(
        pending.exportPermission,
        multiState.exportPermission
      );
    }
    setMultiStatus(
      pending.role === 'master'
        ? '共有モード: 前回のマスター接続を復元中…'
        : (pending.role === 'spectator'
          ? '共有モード: 前回の視聴接続を復元中…'
          : '共有モード: 前回の参加接続を復元中…'),
      'info'
    );
    syncMultiControls();
    window.setTimeout(() => {
      connectMultiSessionAs(pending.role, { allowGuestJoin: pending.role === 'guest' });
    }, 80);
  }

  function ensureMultiClientId() {
    if (canUseSessionStorage) {
      try {
        const saved = window.localStorage.getItem(MULTI_CLIENT_ID_STORAGE_KEY);
        if (typeof saved === 'string' && saved.trim()) {
          return saved.trim();
        }
      } catch (error) {
        // Ignore storage errors.
      }
    }
    const generated = crypto.randomUUID
      ? crypto.randomUUID()
      : `multi-${Math.random().toString(36).slice(2, 12)}`;
    if (canUseSessionStorage) {
      try {
        window.localStorage.setItem(MULTI_CLIENT_ID_STORAGE_KEY, generated);
      } catch (error) {
        // Ignore storage errors.
      }
    }
    return generated;
  }

  function generateMultiProjectKey() {
    const alphabet = 'abcdefghijklmnopqrstuvwxyz0123456789';
    const randomLength = 3;
    let randomPart = '';
    if (globalThis.crypto && typeof globalThis.crypto.getRandomValues === 'function') {
      const bytes = new Uint8Array(randomLength);
      globalThis.crypto.getRandomValues(bytes);
      randomPart = Array.from(bytes, byte => alphabet[byte % alphabet.length]).join('');
    } else {
      while (randomPart.length < randomLength) {
        randomPart += Math.random().toString(36).slice(2);
      }
      randomPart = randomPart.slice(0, randomLength);
    }
    const timePart = Date.now().toString(36).slice(-6).padStart(6, '0');
    return normalizeMultiProjectKey(`${timePart}-${randomPart}`);
  }

  function isMultiMasterMode() {
    return multiState.connected && multiState.role === 'master';
  }

  function isMultiGuestMode() {
    return multiState.connected && multiState.role === 'guest';
  }

  function canCurrentClientRequestGuestRole() {
    return false;
  }

  function clearMultiJoinRequests() {
    if (multiState.pendingJoinRequests instanceof Map) {
      multiState.pendingJoinRequests.clear();
    } else {
      multiState.pendingJoinRequests = new Map();
    }
  }

  function removeMultiJoinRequest(clientId) {
    if (!(multiState.pendingJoinRequests instanceof Map)) {
      return false;
    }
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return false;
    }
    return multiState.pendingJoinRequests.delete(normalizedClientId);
  }

  function getPendingMultiJoinRequest(clientId) {
    if (!(multiState.pendingJoinRequests instanceof Map)) {
      return null;
    }
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return null;
    }
    return multiState.pendingJoinRequests.get(normalizedClientId) || null;
  }

  function getPendingMultiAssignmentMoveRequest(clientId) {
    if (!(multiState.pendingAssignmentMoveRequests instanceof Map)) {
      return null;
    }
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return null;
    }
    return multiState.pendingAssignmentMoveRequests.get(normalizedClientId) || null;
  }

  function removePendingMultiAssignmentMoveRequest(clientId) {
    if (!(multiState.pendingAssignmentMoveRequests instanceof Map)) {
      return false;
    }
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return false;
    }
    return multiState.pendingAssignmentMoveRequests.delete(normalizedClientId);
  }

  function clearPendingMultiAssignmentMoveRequests() {
    if (multiState.pendingAssignmentMoveRequests instanceof Map) {
      multiState.pendingAssignmentMoveRequests.clear();
    } else {
      multiState.pendingAssignmentMoveRequests = new Map();
    }
  }

  function upsertPendingMultiAssignmentMoveRequest(
    clientId,
    frameIndexRaw,
    trackIndexRaw,
    sentAt = Date.now(),
    canvasId = ''
  ) {
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return false;
    }
    const frameIndex = Math.max(0, Math.round(Number(frameIndexRaw) || 0));
    const trackIndex = Math.max(0, Math.round(Number(trackIndexRaw) || 0));
    const normalizedCanvasId = normalizeMultiAssignmentCanvasId(
      canvasId,
      getMultiAssignment(normalizedClientId)?.canvasId || getActiveProjectCanvasDocument()?.id || ''
    );
    if (!(multiState.pendingAssignmentMoveRequests instanceof Map)) {
      multiState.pendingAssignmentMoveRequests = new Map();
    }
    multiState.pendingAssignmentMoveRequests.set(normalizedClientId, {
      clientId: normalizedClientId,
      canvasId: normalizedCanvasId,
      frameIndex,
      trackIndex,
      sentAt: Number.isFinite(Number(sentAt)) ? Math.round(Number(sentAt)) : Date.now(),
    });
    return true;
  }

  function prunePendingMultiAssignmentMoveRequests() {
    if (!(multiState.pendingAssignmentMoveRequests instanceof Map) || !multiState.pendingAssignmentMoveRequests.size) {
      return;
    }
    multiState.pendingAssignmentMoveRequests.forEach((entry, clientId) => {
      if (!clientId || clientId === multiState.clientId || isMultiClientBlocked(clientId)) {
        multiState.pendingAssignmentMoveRequests.delete(clientId);
        return;
      }
      const assignment = getMultiAssignment(clientId);
      if (!assignment || assignment.role !== 'guest') {
        multiState.pendingAssignmentMoveRequests.delete(clientId);
        return;
      }
      const canvasId = normalizeMultiAssignmentCanvasId(entry?.canvasId, assignment.canvasId || '');
      const canvasDoc = getProjectCanvasDocumentById(canvasId);
      if (!canvasDoc) {
        multiState.pendingAssignmentMoveRequests.delete(clientId);
        return;
      }
      const frameIndex = Math.round(Number(entry?.frameIndex));
      const trackIndex = Math.round(Number(entry?.trackIndex));
      const canvasFrameCount = Array.isArray(canvasDoc.frames) ? canvasDoc.frames.length : 0;
      if (!canvasFrameCount || !Number.isFinite(frameIndex) || frameIndex < 0 || frameIndex >= canvasFrameCount) {
        multiState.pendingAssignmentMoveRequests.delete(clientId);
        return;
      }
      const layerCount = Array.isArray(canvasDoc.frames[frameIndex]?.layers) ? canvasDoc.frames[frameIndex].layers.length : 0;
      if (!layerCount || !Number.isFinite(trackIndex) || trackIndex < 0 || trackIndex >= layerCount) {
        multiState.pendingAssignmentMoveRequests.delete(clientId);
      }
    });
  }

  function upsertMultiJoinRequest(clientId, name = '', sentAt = Date.now()) {
    const normalizedClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!normalizedClientId) {
      return false;
    }
    if (!(multiState.pendingJoinRequests instanceof Map)) {
      multiState.pendingJoinRequests = new Map();
    }
    const next = {
      clientId: normalizedClientId,
      name: normalizeMultiParticipantName(name, DEFAULT_MULTI_PARTICIPANT_NAME),
      sentAt: Number.isFinite(Number(sentAt)) ? Math.round(Number(sentAt)) : Date.now(),
    };
    multiState.pendingJoinRequests.set(normalizedClientId, next);
    return true;
  }

  function pruneMultiJoinRequests() {
    if (!(multiState.pendingJoinRequests instanceof Map) || !multiState.pendingJoinRequests.size) {
      return;
    }
    const now = Date.now();
    const onlineClientIds = multiState.participants instanceof Map
      ? new Set(Array.from(multiState.participants.keys()))
      : new Set();
    multiState.pendingJoinRequests.forEach((entry, clientId) => {
      if (!clientId || clientId === multiState.clientId) {
        multiState.pendingJoinRequests.delete(clientId);
        return;
      }
      if (isMultiClientBlocked(clientId)) {
        multiState.pendingJoinRequests.delete(clientId);
        return;
      }
      if (onlineClientIds.size && !onlineClientIds.has(clientId)) {
        const sentAt = Number(entry?.sentAt) || 0;
        if ((now - sentAt) > 10000) {
          multiState.pendingJoinRequests.delete(clientId);
        }
        return;
      }
      const assignment = getMultiAssignment(clientId);
      if (assignment?.role === 'guest' || assignment?.role === 'master') {
        multiState.pendingJoinRequests.delete(clientId);
      }
    });
  }

  function getSelectedMultiJoinRequestClientId() {
    if (!(dom.controls.multiJoinRequestTarget instanceof HTMLSelectElement)) {
      return '';
    }
    return (dom.controls.multiJoinRequestTarget.value || '').trim();
  }

  function syncMultiJoinRequestControls() {
    const requestField = dom.controls.multiJoinRequestField;
    const requestButton = dom.controls.multiRequestGuestRole;
    const requestHint = dom.controls.multiJoinRequestHint;
    if (requestField instanceof HTMLElement) {
      requestField.hidden = true;
    }
    if (requestButton instanceof HTMLButtonElement) {
      requestButton.disabled = true;
        requestButton.textContent = localizeText('そのまま編集できます', 'Edit Immediately');
    }
    if (requestHint instanceof HTMLElement) {
      requestHint.textContent = localizeText(
        '共有リンクを開いた人は、そのまま編集できます。',
        'Anyone who opens the invite link can edit immediately.'
      );
    }

    const requestSelect = dom.controls.multiJoinRequestTarget;
    const approveButton = dom.controls.multiJoinRequestApprove;
    const rejectButton = dom.controls.multiJoinRequestReject;
    if (requestSelect instanceof HTMLSelectElement) {
      requestSelect.innerHTML = '';
      requestSelect.disabled = true;
    }
    if (approveButton instanceof HTMLButtonElement) {
      approveButton.disabled = true;
      approveButton.hidden = true;
    }
    if (rejectButton instanceof HTMLButtonElement) {
      rejectButton.disabled = true;
      rejectButton.hidden = true;
    }
  }

  async function sendMultiJoinRequestResult(targetClientId, decision = 'queued') {
    if (!isMultiMasterMode()) {
      return false;
    }
    const normalizedClientId = typeof targetClientId === 'string' ? targetClientId.trim() : '';
    if (!normalizedClientId || normalizedClientId === multiState.clientId) {
      return false;
    }
    const normalizedDecision = typeof decision === 'string' ? decision.trim().slice(0, 32) : 'queued';
    return sendMultiBroadcast('join-request-result', {
      projectKey: multiState.projectKey,
      clientId: multiState.clientId,
      targetClientId: normalizedClientId,
      decision: normalizedDecision,
      sentAt: Date.now(),
    });
  }

  async function sendMultiGuestJoinRequest() {
    if (!canCurrentClientRequestGuestRole()) {
      setMultiStatus(
        localizeText(
          '共有モード: 参加リクエストは視聴者のみ送信できます',
          'Collab mode: join requests can only be sent by viewers'
        ),
        'warn'
      );
      return false;
    }
    if (multiState.joinRequestPending) {
      setMultiStatus(
        localizeText(
          '共有モード: 参加リクエストは送信済みです',
          'Collab mode: join request already sent'
        ),
        'info'
      );
      return false;
    }
    const now = Date.now();
    if (now < (multiState.joinRequestCooldownUntil || 0)) {
      setMultiStatus(
        localizeText(
          '共有モード: リクエストを送信しすぎています。少し待ってください',
          'Collab mode: too many requests sent. Please wait a moment.'
        ),
        'warn'
      );
      return false;
    }
    const sentAt = Date.now();
    multiState.joinRequestPending = true;
    multiState.joinRequestCooldownUntil = sentAt + MULTI_JOIN_REQUEST_COOLDOWN_MS;
    syncMultiJoinRequestControls();
    const sent = await sendMultiBroadcast('join-request', {
      projectKey: multiState.projectKey,
      clientId: multiState.clientId,
      name: getLocalMultiParticipantName(),
      sentAt,
    });
    if (!sent) {
      multiState.joinRequestPending = false;
      syncMultiJoinRequestControls();
      setMultiStatus(
        localizeText(
          '共有モード: 参加リクエストの送信に失敗しました',
          'Collab mode: failed to send join request'
        ),
        'error'
      );
      return false;
    }
    const requestComment = {
      projectKey: multiState.projectKey,
      clientId: multiState.clientId,
      role: normalizeMultiRole(multiState.role, 'spectator'),
      name: getLocalMultiParticipantName(),
      avatarId: getLocalMultiParticipantAvatarId(),
      text: localizeText(
        '参加者に上がりたいです。承認お願いします。',
        'I want to join as a participant. Please approve.'
      ),
      sentAt: Date.now(),
    };
    appendMultiCommentEntry(requestComment);
    renderMultiComments();
    sendMultiBroadcast('comment', requestComment);
    setMultiStatus(
      localizeText(
        '共有モード: 参加リクエストを送信しました',
        'Collab mode: join request sent'
      ),
      'success'
    );
    return true;
  }

  async function approveMultiJoinRequest(clientId) {
    if (!isMultiMasterMode()) {
      return false;
    }
    const targetClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!targetClientId) {
      setMultiStatus(
        localizeText(
          '共有モード: 承認対象を選択してください',
          'Collab mode: select a request to approve'
        ),
        'warn'
      );
      return false;
    }
    const promoted = await forceMultiParticipantRole(targetClientId, 'guest');
    if (!promoted) {
      return false;
    }
    removeMultiJoinRequest(targetClientId);
    syncMultiJoinRequestControls();
    await sendMultiJoinRequestResult(targetClientId, 'approved');
    return true;
  }

  async function approveSelectedMultiJoinRequest() {
    return approveMultiJoinRequest(getSelectedMultiJoinRequestClientId());
  }

  async function rejectMultiJoinRequest(clientId) {
    if (!isMultiMasterMode()) {
      return false;
    }
    const targetClientId = typeof clientId === 'string' ? clientId.trim() : '';
    if (!targetClientId) {
      setMultiStatus(
        localizeText(
          '共有モード: 却下対象を選択してください',
          'Collab mode: select a request to reject'
        ),
        'warn'
      );
      return false;
    }
    removeMultiJoinRequest(targetClientId);
    syncMultiJoinRequestControls();
    await sendMultiRoleChangeNotice(targetClientId, 'spectator', 'master-reject-request');
    await sendMultiJoinRequestResult(targetClientId, 'rejected');
    setMultiStatus(
      localizeText(
        '共有モード: 参加リクエストを却下しました',
        'Collab mode: join request rejected'
      ),
      'info'
    );
    return true;
  }

  async function rejectSelectedMultiJoinRequest() {
    return rejectMultiJoinRequest(getSelectedMultiJoinRequestClientId());
  }

  function isMultiReplicaRole(role) {
    return role === 'guest' || role === 'spectator';
  }

  function getMultiRoleCapabilities(role = multiState.role) {
    if (isSharedProjectCollaborativeMode()) {
      const normalizedRole = normalizeMultiRole(role, getCurrentSharedProjectUiRole());
      return {
        role: normalizedRole,
        isMaster: normalizedRole === 'master',
        isGuest: normalizedRole === 'guest',
        isSpectator: normalizedRole === 'spectator',
        isReplica: false,
        canBroadcastAuthoritativeState: false,
        canReceiveAuthoritativeState: false,
        canRespondToMasterStateRequest: false,
        canReceiveGuestPatch: false,
        canReceiveMasterPatch: false,
        canModerateParticipants: false,
        canSendDrawPatch: false,
        canSendComments: true,
      };
    }
    const normalizedRole = normalizeMultiRole(role, 'guest');
    const isMaster = normalizedRole === 'master';
    const isGuest = normalizedRole === 'guest';
    const isSpectator = normalizedRole === 'spectator';
    return {
      role: normalizedRole,
      isMaster,
      isGuest,
      isSpectator,
      isReplica: isGuest || isSpectator,
      canBroadcastAuthoritativeState: isMaster,
      canReceiveAuthoritativeState: isGuest || isSpectator,
      canRespondToMasterStateRequest: isGuest || isSpectator,
      canReceiveGuestPatch: isMaster || isGuest || isSpectator,
      canReceiveMasterPatch: isGuest || isSpectator,
      canModerateParticipants: isMaster,
      canSendDrawPatch: isGuest,
      canSendComments: isMaster || isGuest || isSpectator,
    };
  }

  function isMultiPayloadForCurrentProject(payload) {
    if (prefersSharedProjectFlow()) {
      return false;
    }
    if (!payload || typeof payload !== 'object') {
      return false;
    }
    const payloadProjectKey = normalizeMultiProjectKey(payload.projectKey);
    return !payloadProjectKey || payloadProjectKey === multiState.projectKey;
  }

  function isMultiPayloadTargetedToCurrentClient(payload) {
    if (!payload || typeof payload !== 'object') {
      return false;
    }
    const targetClientId = typeof payload.targetClientId === 'string' ? payload.targetClientId.trim() : '';
    return !targetClientId || targetClientId === multiState.clientId;
  }

  function clearMultiLocalSnapshotBeforeReplica() {
    multiState.localSnapshotBeforeReplica = null;
    multiState.localUnsavedBeforeReplica = false;
  }

  function captureMultiLocalSnapshotBeforeReplica() {
    if (multiState.localSnapshotBeforeReplica) {
      return true;
    }
    if (!Array.isArray(state.frames) || !state.frames.length) {
      return false;
    }
    try {
      const snapshot = compressHistorySnapshot(makeHistorySnapshot({ clonePixelData: true }));
      if (!snapshot) {
        return false;
      }
      multiState.localSnapshotBeforeReplica = snapshot;
      multiState.localUnsavedBeforeReplica = hasDocumentUnsavedChanges();
      return true;
    } catch (error) {
      return false;
    }
  }

  function restoreMultiLocalSnapshotBeforeReplica() {
    const compressed = multiState.localSnapshotBeforeReplica;
    const wasUnsaved = Boolean(multiState.localUnsavedBeforeReplica);
    clearMultiLocalSnapshotBeforeReplica();
    if (!compressed || typeof compressed !== 'object') {
      return false;
    }
    let snapshot = null;
    try {
      snapshot = decompressHistorySnapshot(compressed);
    } catch (error) {
      return false;
    }
    if (!snapshot || !Array.isArray(snapshot.frames) || !snapshot.frames.length) {
      return false;
    }
    applyHistorySnapshot(snapshot);
    history.past = [];
    history.future = [];
    history.pending = null;
    clearTimelapseRecording({ silent: true, scope: 'all' });
    if (wasUnsaved) {
      markDocumentUnsavedChange();
    } else {
      resetDocumentUnsavedChanges();
    }
    updateHistoryButtons();
    markAutosaveDirty();
    scheduleAutosaveSnapshot();
    return true;
  }

  function isMultiMasterCurrentlyOnline() {
    if (!multiState.connected) {
      return false;
    }
    const masterClientId = typeof multiState.masterClientId === 'string'
      ? multiState.masterClientId.trim()
      : '';
    if (!masterClientId) {
      return false;
    }
    const participant = multiState.participants instanceof Map
      ? multiState.participants.get(masterClientId)
      : null;
    return Boolean(participant && participant.role === 'master');
  }

  function canCurrentGuestFreelyMoveAssignedCell() {
    if (isSharedProjectCollaborativeMode()) {
      return true;
    }
    return isMultiGuestMode()
      && normalizeMultiParticipantFreeCellMove(
        multiState.participantFreeCellMove,
        MULTI_DEFAULT_PARTICIPANT_FREE_CELL_MOVE
      );
  }

  function announceMultiCanvasEditRestriction() {
    const sharedStructureBlockReason = getSharedProjectStructureChangeBlockReason();
    if (sharedStructureBlockReason) {
      announceSharedProjectStructureChangeBlocked(sharedStructureBlockReason);
      return;
    }
    setMultiStatus(
      localizeText(
        '参加/視聴モードではマルチキャンバスの変更はマスターのみ操作できます',
        'In participant/viewer mode, only the master can change multi canvas settings'
      ),
      'warn'
    );
  }

  function getSharedProjectStructureChangeBlockReason({ ignoreLocalInteraction = false } = {}) {
    if (!isSharedProjectCollaborativeMode()) {
      return '';
    }
    if (activeSharedProjectOpenInProgress) return 'open-in-progress';
    if (activeSharedProjectOpenReadOnly || !canCurrentSharedProjectEdit()) return 'read-only';
    if (!activeSharedProjectDocumentLoaded || !hasUsableActiveSharedProjectDocumentState()) return 'document-not-ready';
    if (!ignoreLocalInteraction) {
      if (pointerState.active) return 'local-pointer-active';
      if (typeof hasPendingSelectionMove === 'function' && hasPendingSelectionMove()) return 'selection-move-pending';
      if (history.pending) return 'history-pending';
    }
    if (sharedProjectOpCommitInFlight || hasSharedProjectLocalInFlightOps() || sharedProjectPendingLocalOps.length > 0 || sharedProjectSyncInFlight) return 'local-op-in-flight';
    if (sharedProjectPendingRemoteOps.size > 0) return 'remote-op-pending';
    if (sharedProjectRefreshInFlight || sharedProjectSnapshotReplayInFlight || sharedProjectRecoveryInProgress) return 'remote-sync-in-flight';
    if (sharedProjectReconnectRecoveryPromise || sharedProjectWakeRecoveryPromise || sharedProjectImmediateRecoveryPromise) return 'remote-sync-in-flight';
    if (sharedProjectDeferRealtimeUntilSynced || activeSharedProjectSyncState !== 'synced' || !activeSharedProjectSynced) return 'not-synced';
    return '';
  }

  function announceSharedProjectStructureChangeBlocked(reason = '') {
    const normalizedReason = String(reason || '').trim();
    const drawingReason = normalizedReason === 'local-pointer-active'
      || normalizedReason === 'selection-move-pending'
      || normalizedReason === 'history-pending';
    setMultiStatus(
      drawingReason
        ? localizeText(
          '共有プロジェクトの構造変更は現在の操作を確定してから実行してください。',
          'Shared structure changes are available after the current local action is committed.'
        )
        : localizeText(
          '共有プロジェクトの構造変更は同期が完了してから実行してください。',
          'Shared structure changes are available after sync settles.'
        ),
      'warn'
    );
  }

  function canCurrentClientEditProjectStructure({ announce = false, ignoreLocalInteraction = false } = {}) {
    if (isSharedProjectCollaborativeMode()) {
      if (!canCurrentSharedProjectEdit()) {
        if (announce) {
          announceSharedProjectEditPermissionBlocked();
        }
        return false;
      }
      const blockReason = getSharedProjectStructureChangeBlockReason({ ignoreLocalInteraction });
      if (blockReason) {
        if (announce) {
          announceSharedProjectStructureChangeBlocked(blockReason);
        }
        return false;
      }
      return true;
    }
    return !isMultiReadOnlyMode();
  }

  function canCurrentClientImportExternalData() {
    if (isSharedProjectCollaborativeMode()) {
      return canCurrentSharedProjectEdit();
    }
    return !isMultiReadOnlyMode();
  }

  function isMultiMasterProjectReplacementBlocked() {
    if (prefersSharedProjectFlow()) {
      return false;
    }
    return isMultiMasterMode();
  }

  function ensureCurrentClientCanReplaceActiveProject({ announce = true } = {}) {
    if (!isMultiMasterProjectReplacementBlocked()) {
      return true;
    }
    if (announce) {
      setMultiStatus(
        localizeText(
          '共有中のメインプロジェクトを保護するため、マスター接続中は別プロジェクトへ切替できません。先に共有を切断してください。',
          'To protect the shared main project, you cannot switch to another project while connected as master. Disconnect collab first.'
        ),
        'warn'
      );
    }
    return false;
  }

  function normalizeMultiBlockedClientIds(rawBlockedClientIds) {
    const blocked = new Set();
    if (!Array.isArray(rawBlockedClientIds)) {
      return blocked;
    }
    rawBlockedClientIds.forEach(value => {
      if (typeof value !== 'string') {
        return;
      }
      const normalized = value.trim();
      if (!normalized) {
        return;
      }
      blocked.add(normalized);
    });
    return blocked;
  }

  function serializeMultiBlockedClientIds() {
    if (!(multiState.blockedClientIds instanceof Set) || !multiState.blockedClientIds.size) {
      return [];
    }
    return Array.from(multiState.blockedClientIds.values())
      .filter(value => typeof value === 'string' && value.trim())
      .map(value => value.trim())
      .sort((a, b) => a.localeCompare(b));
  }

  function isMultiClientBlocked(clientId) {
    if (!clientId || !(multiState.blockedClientIds instanceof Set) || !multiState.blockedClientIds.size) {
      return false;
    }
    return multiState.blockedClientIds.has(clientId);
  }

  function normalizeMultiParticipantName(name, fallbackName = DEFAULT_MULTI_PARTICIPANT_NAME) {
    if (typeof name === 'string') {
      const trimmed = name.trim();
      if (trimmed) {
        return trimmed.slice(0, 32);
      }
    }
    if (typeof fallbackName === 'string') {
      const trimmedFallback = fallbackName.trim();
      if (trimmedFallback) {
        return trimmedFallback.slice(0, 32);
      }
    }
    return DEFAULT_MULTI_PARTICIPANT_NAME;
  }

  const pixieedProfileLocalUtilsModule = window.PiXiEEDrawModules?.pixieedProfileLocalUtils?.createPixieedProfileLocalUtils?.({
  get PIXIEED_AVATAR_STORAGE_KEY() { return PIXIEED_AVATAR_STORAGE_KEY; },
  set PIXIEED_AVATAR_STORAGE_KEY(value) { PIXIEED_AVATAR_STORAGE_KEY = value; },
  get PIXIEED_NICKNAME_STORAGE_KEY() { return PIXIEED_NICKNAME_STORAGE_KEY; },
  set PIXIEED_NICKNAME_STORAGE_KEY(value) { PIXIEED_NICKNAME_STORAGE_KEY = value; },
  get PIXIEED_X_URL_STORAGE_KEY() { return PIXIEED_X_URL_STORAGE_KEY; },
  set PIXIEED_X_URL_STORAGE_KEY(value) { PIXIEED_X_URL_STORAGE_KEY = value; },
  get accountState() { return accountState; },
  set accountState(value) { accountState = value; },
  get canUseSessionStorage() { return canUseSessionStorage; },
  set canUseSessionStorage(value) { canUseSessionStorage = value; },
  }) || {};

  function normalizePixieedAvatarId(value) {
    return pixieedProfileLocalUtilsModule.normalizePixieedAvatarId(...arguments);
  }

  function resolvePixieedAvatarSrcFromId(value) {
    return pixieedProfileLocalUtilsModule.resolvePixieedAvatarSrcFromId(...arguments);
  }

  function readPixieedLocalNickname() {
    return pixieedProfileLocalUtilsModule.readPixieedLocalNickname(...arguments);
  }

  function writePixieedLocalNickname(value) {
    return pixieedProfileLocalUtilsModule.writePixieedLocalNickname(...arguments);
  }

  function readPixieedLocalAvatarId() {
    return pixieedProfileLocalUtilsModule.readPixieedLocalAvatarId(...arguments);
  }

  function writePixieedLocalAvatarId(value) {
    return pixieedProfileLocalUtilsModule.writePixieedLocalAvatarId(...arguments);
  }

  function readPixieedLocalXUrl() {
    return pixieedProfileLocalUtilsModule.readPixieedLocalXUrl(...arguments);
  }

  function writePixieedLocalXUrl(value) {
    return pixieedProfileLocalUtilsModule.writePixieedLocalXUrl(...arguments);
  }

  function readPixieedAccountNickname() {
    return pixieedProfileLocalUtilsModule.readPixieedAccountNickname(...arguments);
  }

  function readPixieedAccountAvatarId() {
    return pixieedProfileLocalUtilsModule.readPixieedAccountAvatarId(...arguments);
  }

  function readPixieedAccountXUrl() {
    return pixieedProfileLocalUtilsModule.readPixieedAccountXUrl(...arguments);
  }

  function isMissingColumn(error, column) {
    return pixieedProfileLocalUtilsModule.isMissingColumn(...arguments);
  }

  function isMissingTable(error, table) {
    return pixieedProfileLocalUtilsModule.isMissingTable(...arguments);
  }

  function shouldIgnorePixieedProfileError(error) {
    return pixieedProfileLocalUtilsModule.shouldIgnorePixieedProfileError(...arguments);
  }

  function shouldDisableSharedProjectsBackend(error) {
    return pixieedProfileLocalUtilsModule.shouldDisableSharedProjectsBackend(...arguments);
  }

  function isMissingRpcFunction(error, functionName = '') {
    return pixieedProfileLocalUtilsModule.isMissingRpcFunction(...arguments);
  }

  function handleSharedProjectsBackendError(error, context = '') {
    if (shouldDisableSharedProjectsBackend(error)) {
      supportsSharedProjectsBackend = false;
      disconnectActiveSharedProjectRealtimeChannel().catch(() => {});
    }
    const status = Number(error?.status || 0);
    const message = String(error?.message || '');
    const code = String(error?.code || '');
    const details = String(error?.details || '');
    const hint = String(error?.hint || '');
    const locationOrigin = typeof window !== 'undefined' && window.location
      ? String(window.location.origin || '')
      : '';
    const locationHref = typeof window !== 'undefined' && window.location
      ? String(window.location.href || '')
      : '';
    const referrer = typeof document !== 'undefined' ? String(document.referrer || '') : '';
    const visibilityState = typeof document !== 'undefined' ? String(document.visibilityState || '') : '';
    const online = typeof navigator !== 'undefined' ? Boolean(navigator.onLine) : null;
    const userAgent = typeof navigator !== 'undefined' ? String(navigator.userAgent || '') : '';
    if (isRecoverableSharedBackendPreflightError(error)) {
      console.debug('[shared-backend] recoverable network error', {
        context,
        status,
        code,
        message,
        locationOrigin,
        locationHref,
        visibilityState,
        online,
      });
      if (activeSharedProjectKey) {
        setActiveSharedProjectSyncState('catching-up', { announce: true });
        queueSharedProjectReconnectRecovery(`network-${context || 'backend'}`, { immediate: false });
      }
      return;
    }
    if (accountState.isLoggedIn) {
      if (code === '42804' && context === 'claim-shared-session') {
        setMultiStatus(
          localizeText(
            '共有機能のサーバー定義が古いため、この共有プロジェクトを開けません。サーバー更新後に再度お試しください。',
            'This shared project cannot be opened because the shared backend function definition is outdated. Please try again after the server is updated.'
          ),
          'error'
        );
      } else if (shouldDisableSharedProjectsBackend(error)) {
        setMultiStatus(
          localizeText(
            '共有機能の本番データベースが未反映です。shared project の移行が本番に入っていません。',
            'Shared mode is not available yet because the production database is missing the shared project migration.'
          ),
          'error'
        );
      } else if (message.includes('shared_project_member_limit_reached')) {
        setMultiStatus(
          localizeText(
            'この共有プロジェクトは参加人数の上限に達しています。無料枠はマスターと参加者1人の最大2人までです。',
            'This shared project has reached its member limit. The free tier allows up to 2 people: master plus 1 participant.'
          ),
          'warn'
        );
      } else if (status >= 500) {
        setMultiStatus(
          localizeText(
            '共有機能のサーバー側でエラーが発生しています。時間をおいて再試行してください。',
            'The shared project backend returned a server error. Please try again later.'
          ),
          'error'
        );
      } else if (message) {
        setMultiStatus(
          localizeText(
            `共有機能エラー: ${message}`,
            `Shared mode error: ${message}`
          ),
          'error'
        );
      }
    }
    if (context) {
      console.warn(`Shared project backend error (${context})`, error);
      console.debug('[shared-backend] error detail', {
        context,
        status,
        code,
        message,
        details,
        hint,
        locationOrigin,
        locationHref,
        referrer,
        visibilityState,
        online,
        userAgent,
        accountLoggedIn: Boolean(accountState.isLoggedIn),
        accountUserId: accountState.userId || '',
        accountAnonymous: Boolean(accountState.isAnonymous),
      });
    } else {
      console.warn('Shared project backend error', error);
      console.debug('[shared-backend] error detail', {
        status,
        code,
        message,
        details,
        hint,
        locationOrigin,
        locationHref,
        referrer,
        visibilityState,
        online,
        userAgent,
        accountLoggedIn: Boolean(accountState.isLoggedIn),
        accountUserId: accountState.userId || '',
        accountAnonymous: Boolean(accountState.isAnonymous),
      });
    }
  }

  function canUseSharedProjectsBackend() {
    return sharedRuntimeUtilsModule.canUseSharedProjectsBackend(...arguments);
  }

  function isRecoverableSharedBackendPreflightError(error) {
    return sharedRuntimeUtilsModule.isRecoverableSharedBackendPreflightError(...arguments);
  }

  async function waitForSharedOpenRetry(delayMs = 240) {
    await new Promise(resolve => {
      window.setTimeout(resolve, Math.max(48, Math.round(Number(delayMs) || 240)));
    });
  }

  function scheduleSharedProjectLatestRecovery(entry = null, {
    reason = 'recent-fallback-recovery',
    immediate = false,
  } = {}) {
    const normalizedEntry = normalizeSharedRecentProjectEntry(entry);
    const projectKey = normalizeMultiProjectKey(normalizedEntry?.sharedProjectKey || activeSharedProjectKey || '');
    if (!projectKey) {
      return;
    }
    const run = async () => {
      try {
        if (!accountState.isLoggedIn || accountState.isAnonymous) {
          return;
        }
        await ensurePixieedAccountReady({ forceRefresh: true, silent: true });
        if (!await ensureSharedProjectBackendSession()) {
          return;
        }
        const refreshedEntry = normalizedEntry
          ? (await refreshSharedRecentProjectEntryFromBackend(normalizedEntry) || normalizedEntry)
          : null;
        if (refreshedEntry?.sharedProjectBackendId && activeSharedProjectKey === projectKey && !activeSharedProjectId) {
          setActiveSharedProjectSession(
            projectKey,
            activeSharedProjectRevision,
            activeSharedProjectStructureRevision,
            refreshedEntry.sharedProjectBackendId
          );
        }
        if (activeSharedProjectKey === projectKey) {
          const restoredRevision = Math.max(0, Math.round(Number(
            refreshedEntry?.sharedProjectRevision
            || normalizedEntry?.sharedProjectRevision
            || activeSharedProjectRevision
            || 0
          )));
          const restoredStructureRevision = Math.max(0, Math.round(Number(
            refreshedEntry?.sharedProjectStructureRevision
            || normalizedEntry?.sharedProjectStructureRevision
            || activeSharedProjectStructureRevision
            || 0
          )));
          let latestProject = null;
          if (refreshedEntry?.sharedProjectInviteToken) {
            latestProject = await loadSharedProjectSnapshotRecordByInvite(refreshedEntry.sharedProjectInviteToken, {
              createIfMissing: false,
              title: createSharedProjectSnapshotTitle(refreshedEntry.name || state.documentName || DEFAULT_DOCUMENT_NAME),
            });
          }
          if (!latestProject?.project_key) {
            latestProject = await loadSharedProjectSnapshotRecord(projectKey, {
              createIfMissing: false,
              title: createSharedProjectSnapshotTitle(refreshedEntry?.name || state.documentName || DEFAULT_DOCUMENT_NAME),
            });
          }
          const latestRevision = Math.max(0, Math.round(Number(latestProject?.latest_revision) || 0));
          const latestStructureRevision = Math.max(0, Math.round(Number(latestProject?.latest_structure_revision) || 0));
          if (
            latestProject?.project_key
            && latestStructureRevision === restoredStructureRevision
            && latestRevision > restoredRevision
          ) {
            const replayed = await applySharedProjectOpsSinceRevision(latestProject, restoredRevision);
            if (replayed) {
              return;
            }
          }
          await refreshActiveSharedProjectSnapshot({ force: true, reason });
        }
      } catch (error) {
        console.warn('Failed to recover latest shared project state after local fallback', error);
      }
    };
    window.setTimeout(() => {
      run().catch(() => {});
    }, immediate ? 0 : 400);
  }

  function canLookupSharedProjectsBackend() {
    return supportsSharedProjectsBackend;
  }

  function hasSharedProjectLocalWorkInFlight() {
    return (
      hasDocumentUnsavedChanges()
      || pointerState.active
      || sharedProjectOpCommitInFlight
      || sharedProjectPendingLocalOps.length > 0
      || sharedProjectSyncInFlight
    );
  }

  function hasSharedProjectHardLocalWorkInFlight() {
    return (
      pointerState.active
      || sharedProjectOpCommitInFlight
      || sharedProjectPendingLocalOps.length > 0
      || sharedProjectSyncInFlight
    );
  }

  function hasSharedProjectRemoteApplyBlockingWork() {
    return (
      pointerState.active
      || sharedProjectSyncInFlight
    );
  }

  function hasSharedProjectStructureLocalWorkInFlight() {
    if (!isSharedProjectCollaborativeMode()) {
      return false;
    }
    if (sharedProjectLocalInFlightOps instanceof Map) {
      for (const entry of sharedProjectLocalInFlightOps.values()) {
        if (entry?.opType === 'structure') {
          return true;
        }
      }
    }
    if (Array.isArray(sharedProjectPendingLocalOps)) {
      return sharedProjectPendingLocalOps.some(entry => {
        const opRecord = entry?.op || entry || null;
        const opType = entry?.opType || classifySharedProjectOpType(String(entry?.historyLabel || opRecord?.historyLabel || ''));
        return opType === 'structure';
      });
    }
    return false;
  }

  function setActiveSharedProjectSyncState(nextState = 'idle', { announce = false } = {}) {
    const normalizedState = nextState === 'catching-up' || nextState === 'synced' ? nextState : 'idle';
    activeSharedProjectSyncState = normalizedState;
    activeSharedProjectSynced = normalizedState === 'synced';
    if (normalizedState === 'catching-up') {
      if (!sharedProjectCatchingUpStartedAt) {
        sharedProjectCatchingUpStartedAt = Date.now();
      }
      clearSharedProjectDrawReadinessVerification();
    } else {
      sharedProjectCatchingUpStartedAt = 0;
      clearSharedProjectRecoveryReloadTimer();
      if (
        normalizedState === 'synced'
        && activeSharedProjectDocumentLoaded
        && hasUsableActiveSharedProjectDocumentState()
      ) {
        markSharedProjectDrawReadinessVerified('sync-state-synced');
      }
    }
    syncSharedProjectVisibleStatus();
    if (!announce || !isSharedProjectCollaborativeMode()) {
      return;
    }
    if (normalizedState === 'catching-up') {
      setMultiStatus(
        localizeText(
          '共有モード: 最新状態へ同期中… 描画内容は送信待ちとして保護しています',
          'Shared mode: syncing to the latest state... edits are protected while waiting to send.'
        ),
        'info'
      );
      return;
    }
    if (normalizedState === 'synced') {
      if (hasSharedProjectLocalInFlightOps()) {
        setMultiStatus(localizeText('共有モード: 未確定変更あり', 'Shared mode: pending local changes'), 'info');
      } else {
        setMultiStatus(localizeText('共有モード: 最新', 'Shared mode: up to date'), 'success');
      }
    }
  }

  function isSharedProjectCatchingUp(projectKey = '') {
    return isSharedProjectCollaborativeMode(projectKey) && activeSharedProjectSyncState === 'catching-up';
  }

  function isSharedProjectAwaitingReady(projectKey = '') {
    return Boolean(
      isSharedProjectCollaborativeMode(projectKey)
      && (
        sharedProjectDeferRealtimeUntilSynced
        || (
          !activeSharedProjectDocumentLoaded
          && !hasUsableActiveSharedProjectDocumentState()
        )
      )
    );
  }

  function canAcceptSharedProjectLocalDrawOps(projectKey = '', options = {}) {
    const normalizedProjectKey = normalizeMultiProjectKey(projectKey || activeSharedProjectKey || '');
    if (!isSharedProjectCollaborativeMode(normalizedProjectKey)) {
      return true;
    }
    return !getSharedProjectLocalDrawBlockReason(normalizedProjectKey, options);
  }

  function isSharedProjectsBlockedByRuntime() {
    return sharedRuntimeUtilsModule.isSharedProjectsBlockedByRuntime(...arguments);
  }

  function showSharedProjectSunsetDialog() {
    return sharedRuntimeUtilsModule.showSharedProjectSunsetDialog(...arguments);
  }

  function showSharedRuntimeBlockedStatus() {
    return sharedRuntimeUtilsModule.showSharedRuntimeBlockedStatus(...arguments);
  }

  function canApplyIncomingSharedProjectSnapshot({ force = false } = {}) {
    return (
      !(force ? hasSharedProjectHardLocalWorkInFlight() : hasSharedProjectLocalWorkInFlight())
      && !autosaveWriteInFlight
      && !multiState.applyRemoteInProgress
      && !multiState.connecting
    );
  }

  function shouldDeferIncomingSharedProjectRemoteApply() {
    return (
      (!activeSharedProjectDocumentLoaded && !hasUsableActiveSharedProjectDocumentState())
      || hasSharedProjectRemoteApplyBlockingWork()
      || autosaveWriteInFlight
      || multiState.applyRemoteInProgress
      || multiState.connecting
    );
  }

  function clearDeferredSharedProjectRemoteOpsDrain() {
    if (sharedProjectDeferredRemoteOpsTimer !== null) {
      window.clearTimeout(sharedProjectDeferredRemoteOpsTimer);
      sharedProjectDeferredRemoteOpsTimer = null;
    }
    sharedProjectDeferredRemoteOpsDelayMs = 0;
  }

  function trimSharedProjectPendingRemoteOpsCapacity() {
    if (sharedProjectPendingRemoteOps.size <= SHARED_PROJECT_PENDING_REMOTE_OP_LIMIT) {
      return 0;
    }
    const overflow = sharedProjectPendingRemoteOps.size - SHARED_PROJECT_PENDING_REMOTE_OP_LIMIT;
    const removeSeqs = Array.from(sharedProjectPendingRemoteOps.keys())
      .map(seq => Math.max(0, Math.round(Number(seq) || 0)))
      .filter(seq => seq > 0)
      .sort((a, b) => b - a)
      .slice(0, overflow);
    removeSeqs.forEach(seq => sharedProjectPendingRemoteOps.delete(seq));
    console.warn('[shared-realtime] pending-remote-op-cap-pruned', {
      projectKey: activeSharedProjectKey || '',
      removed: removeSeqs.length,
      remaining: sharedProjectPendingRemoteOps.size,
      activeRevision: sharedProjectLastAppliedSeq,
    });
    return removeSeqs.length;
  }

  function rememberPendingSharedProjectRemoteOp(seq, opRecord, _reason = '') {
    const normalizedSeq = Math.max(0, Math.round(Number(seq) || 0));
    if (!normalizedSeq || normalizedSeq <= sharedProjectLastAppliedSeq) {
      return false;
    }
    sharedProjectPendingRemoteOps.set(normalizedSeq, opRecord);
    if (normalizedSeq > sharedProjectLastAppliedSeq + 1) {
      scheduleSharedProjectOpsRescueRetry(48, _reason || 'pending-remote-gap');
    }
    const prunedCount = trimSharedProjectPendingRemoteOpsCapacity();
    if (prunedCount > 0) {
      scheduleSharedProjectOpsRescueRetry(1000, 'pending-remote-cap-pruned');
    }
    return true;
  }

  function prunePendingSharedProjectRemoteState(minRevision = 0) {
    const normalizedMinRevision = Math.max(0, Math.round(Number(minRevision) || 0));
    if (sharedProjectPendingRemoteOps.size) {
      Array.from(sharedProjectPendingRemoteOps.keys()).forEach(seq => {
        if (Math.max(0, Math.round(Number(seq) || 0)) <= normalizedMinRevision) {
          sharedProjectPendingRemoteOps.delete(seq);
        }
      });
    }
    if (sharedProjectPendingProvisionalOps.size) {
      sharedProjectPendingProvisionalOps.clear();
    }
  }

  function resetPendingSharedProjectRemoteState() {
    clearDeferredSharedProjectRemoteOpsDrain();
    if (sharedProjectPendingRemoteOps.size) {
      sharedProjectPendingRemoteOps.clear();
    }
    if (sharedProjectPendingProvisionalOps.size) {
      sharedProjectPendingProvisionalOps.clear();
    }
  }

  function pruneSharedProjectConfirmedOpStateAfterRevision(revision = 0) {
    const normalizedRevision = Math.max(0, Math.round(Number(revision) || 0));
    Array.from(sharedProjectSeenOpSeqById.entries()).forEach(([opId, seq]) => {
      if (Math.max(0, Math.round(Number(seq) || 0)) > normalizedRevision) {
        sharedProjectSeenOpSeqById.delete(opId);
        sharedProjectSeenOpIds.delete(opId);
      }
    });
    sharedProjectAppliedProvisionalOpIds.clear();
  }

  function clearSharedProjectStructureMismatchRecovery() {
    if (sharedProjectStructureMismatchTimer !== null) {
      window.clearTimeout(sharedProjectStructureMismatchTimer);
      sharedProjectStructureMismatchTimer = null;
    }
  }

  function scheduleSharedProjectStructureMismatchRecovery(delayMs = 96) {
    if (sharedProjectStructureMismatchTimer !== null || !activeSharedProjectKey) {
      return;
    }
    sharedProjectStructureMismatchTimer = window.setTimeout(() => {
      sharedProjectStructureMismatchTimer = null;
      if (!activeSharedProjectKey) {
        return;
      }
      const initialReplayCount = replayDeferredSharedProjectProvisionalOps();
      if (!sharedProjectPendingProvisionalOps.size) {
        return;
      }
      pollSharedProjectRealtimeOpsRescue({ reason: 'structure-mismatch-op-poll' })
        .then(recovered => {
          const replayedAfterPoll = replayDeferredSharedProjectProvisionalOps();
          if (
            recovered
            || initialReplayCount > 0
            || replayedAfterPoll > 0
            || !sharedProjectPendingProvisionalOps.size
          ) {
            if (sharedProjectPendingProvisionalOps.size) {
              scheduleSharedProjectStructureMismatchRecovery(Math.max(96, delayMs));
            }
            return;
          }
          triggerImmediateSharedProjectRecovery('canonical-resync-structure-mismatch').then(refreshed => {
            if (!refreshed) {
              queueSharedProjectRefresh({
                immediate: true,
                reason: 'canonical-resync-structure-mismatch',
                force: true,
              });
            }
          }).catch(() => {
            queueSharedProjectRefresh({
              immediate: true,
              reason: 'canonical-resync-structure-mismatch',
              force: true,
            });
          });
        })
        .catch(() => {
          if (!sharedProjectPendingProvisionalOps.size) {
            return;
          }
          queueSharedProjectRefresh({
            immediate: true,
            reason: 'canonical-resync-structure-mismatch',
            force: true,
          });
        });
    }, Math.max(48, Math.round(Number(delayMs) || 96)));
  }

  function scheduleDeferredSharedProjectRemoteOpsDrain(delayMs = SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_BASE_DELAY_MS) {
    if (sharedProjectDeferredRemoteOpsTimer !== null || !activeSharedProjectKey) {
      return;
    }
    const requestedDelay = Math.max(
      16,
      Math.round(Number(delayMs) || SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_BASE_DELAY_MS)
    );
    const scheduledDelay = clamp(
      sharedProjectDeferredRemoteOpsDelayMs > 0
        ? Math.max(requestedDelay, sharedProjectDeferredRemoteOpsDelayMs)
        : requestedDelay,
      16,
      SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_MAX_DELAY_MS
    );
    sharedProjectDeferredRemoteOpsDelayMs = scheduledDelay;
    sharedProjectDeferredRemoteOpsTimer = window.setTimeout(() => {
      sharedProjectDeferredRemoteOpsTimer = null;
      if (!activeSharedProjectKey) {
        sharedProjectDeferredRemoteOpsDelayMs = 0;
        return;
      }
      if (shouldDeferIncomingSharedProjectRemoteApply()) {
        sharedProjectDeferredRemoteOpsDelayMs = Math.min(
          SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_MAX_DELAY_MS,
          Math.max(SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_BASE_DELAY_MS, scheduledDelay * 2)
        );
        scheduleDeferredSharedProjectRemoteOpsDrain(sharedProjectDeferredRemoteOpsDelayMs);
        return;
      }
      sharedProjectDeferredRemoteOpsDelayMs = 0;
      if (drainPendingSharedProjectRemoteOps()) {
        return;
      }
      if (sharedProjectPendingRemoteOps.size) {
        sharedProjectDeferredRemoteOpsDelayMs = Math.min(
          SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_MAX_DELAY_MS,
          Math.max(SHARED_PROJECT_DEFERRED_REMOTE_DRAIN_BASE_DELAY_MS, scheduledDelay)
        );
        scheduleDeferredSharedProjectRemoteOpsDrain(sharedProjectDeferredRemoteOpsDelayMs);
      }
    }, scheduledDelay);
  }

  function isSharedProjectRealtimePrimaryActive(projectKey = '') {
    ensureBoundSharedProjectSessionFromCurrentState(projectKey);
    const resolvedSharedProjectKey = resolveSharedProjectKeyForCurrentState(projectKey);
    if (!canUseSharedProjectsBackend() || !resolvedSharedProjectKey || !activeSharedProjectKey) {
      return false;
    }
    return resolvedSharedProjectKey === activeSharedProjectKey;
  }

  function isSharedProjectCollaborativeMode(projectKey = '') {
    ensureBoundSharedProjectSessionFromCurrentState(projectKey);
    const normalizedProjectKey = resolveSharedProjectKeyForCurrentState(projectKey);
    if (!normalizedProjectKey) {
      return false;
    }
    return Boolean(
      canUseSharedProjectsBackend()
      && activeSharedProjectKey
      && normalizedProjectKey === activeSharedProjectKey
    );
  }

